+
+  for (const row of rows) {
+    if (row.durationMs > 0) {
+      durations.push(row.durationMs);
+
+      // Categorize by duration as proxy for complexity
+      if (row.durationMs < 5000) {
+        byComplexity["simple"]!.push(row.durationMs);
+      } else if (row.durationMs < 30000) {
